evaluators.evaluation_logic:
const checkpoints = [];

const quoteRequests = JSON.parse(localStorage.getItem('quote_requests') || '[]');
const quotePlans = JSON.parse(localStorage.getItem('quote_plans') || '[]');
const savedQuotes = JSON.parse(localStorage.getItem('saved_quotes') || '[]');

// QuoteRequests matching the task inputs
const matchingRequests = quoteRequests.filter(qr =>
  qr &&
  qr.property_type === 'residential' &&
  qr.zip_code === '94110' &&
  qr.roof_area_sqft === 1200 &&
  qr.average_monthly_bill === 150 &&
  qr.desired_system_size_kw === 5
);
const matchingRequestIds = matchingRequests.map(qr => qr.id);

// Saved quotes originating from those requests via the quote tool
const savedFromMatchingRequests = savedQuotes.filter(sq =>
  sq &&
  sq.source_type === 'quote_tool' &&
  sq.quote_request_id &&
  matchingRequestIds.includes(sq.quote_request_id)
);

// CP1 (0.4): User saved at least one quote generated from a correctly configured 5 kW residential request
checkpoints.push({
  passed: savedFromMatchingRequests.length > 0,
  weight: 0.4
});

// Among those saved quotes, check if any has estimated_monthly_payment <= 120
const qualifyingSaved = savedFromMatchingRequests.filter(sq => {
  const plan = quotePlans.find(p => p.id === sq.quote_plan_id);
  return plan && typeof plan.estimated_monthly_payment === 'number' && plan.estimated_monthly_payment <= 120;
});

// CP2 (0.6): At least one saved quote from the correct request has estimated monthly payment <= $120
checkpoints.push({
  passed: qualifyingSaved.length > 0,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('solar_packages') || '[]');
const savedQuotes = JSON.parse(localStorage.getItem('saved_quotes') || '[]');

// Active residential packages between 6 and 8 kW
const filtered = packages.filter(p =>
  p &&
  p.status === 'active' &&
  p.system_type === 'residential' &&
  typeof p.system_size_kw === 'number' &&
  p.system_size_kw >= 6 &&
  p.system_size_kw <= 8
);

// Sort by total price ascending
filtered.sort((a, b) => {
  const av = a.total_price;
  const bv = b.total_price;
  if (av === bv) return 0;
  return av - bv;
});

// First two results
const firstTwo = filtered.slice(0, 2);
const firstTwoIds = firstTwo.map(p => p.id);

// Among the first two, those under $15,000 with panel warranty >= 20 years
const qualifyingInFirstTwo = firstTwo.filter(p =>
  typeof p.total_price === 'number' &&
  p.total_price < 15000 &&
  typeof p.panel_warranty_years === 'number' &&
  p.panel_warranty_years >= 20
);

// Cheapest qualifying package among the first two (if any)
let cheapestQualifying = null;
if (qualifyingInFirstTwo.length > 0) {
  cheapestQualifying = qualifyingInFirstTwo.reduce((min, p) =>
    !min || p.total_price < min.total_price ? p : min,
    null
  );
}

// Saved quotes that came from solar packages
const savedFromPackages = savedQuotes.filter(sq => sq && sq.source_type === 'solar_package');

// Saved quotes whose source package is one of the first two and meets price & warranty criteria
const qualifyingSaved = savedFromPackages.filter(sq => {
  const pkg = packages.find(p => p.id === sq.source_reference_id);
  return pkg &&
    firstTwoIds.includes(pkg.id) &&
    typeof pkg.total_price === 'number' &&
    pkg.total_price < 15000 &&
    typeof pkg.panel_warranty_years === 'number' &&
    pkg.panel_warranty_years >= 20;
});

// CP1 (0.6): User added to their quote list a package from the first two results that meets the price and warranty thresholds
checkpoints.push({
  passed: qualifyingSaved.length > 0,
  weight: 0.6
});

// CP2 (0.4): The added package is the cheapest qualifying package among the first two
let savedCheapest = false;
if (cheapestQualifying && qualifyingSaved.length > 0) {
  savedCheapest = qualifyingSaved.some(sq => {
    const pkg = packages.find(p => p.id === sq.source_reference_id);
    return pkg && pkg.id === cheapestQualifying.id;
  });
}
checkpoints.push({
  passed: savedCheapest,
  weight: 0.4
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const slots = JSON.parse(localStorage.getItem('consultation_slots') || '[]');
const appointments = JSON.parse(localStorage.getItem('consultation_appointments') || '[]');

// Appointments matching the task context
const matchingAppointments = appointments.filter(a =>
  a &&
  a.consultation_type === 'virtual' &&
  a.property_type === 'residential' &&
  a.zip_code === '78704'
);

function isVirtualWeekdayTen(slot) {
  if (!slot || slot.consultation_type !== 'virtual' || !slot.is_weekday) return false;
  const d = new Date(slot.start_datetime);
  return d.getUTCHours() === 10 && d.getUTCMinutes() === 0;
}

// Slots that are 10:00 AM virtual weekday and were available at some point
const slotsWithPossibleAvailability = slots.filter(s => {
  if (!isVirtualWeekdayTen(s)) return false;
  const wasBookable = s.is_available || appointments.some(a => a.slot_id === s.id);
  return wasBookable;
});

let earliestSlot = null;
slotsWithPossibleAvailability.forEach(s => {
  if (!earliestSlot) {
    earliestSlot = s;
  } else if (new Date(s.start_datetime) < new Date(earliestSlot.start_datetime)) {
    earliestSlot = s;
  }
});

// CP1 (0.5): User booked a virtual residential consultation for ZIP 78704 at 10:00 AM using a slot-based booking
let hasTenAmBooking = false;
if (matchingAppointments.length > 0) {
  hasTenAmBooking = matchingAppointments.some(a => {
    const slot = slots.find(s => s.id === a.slot_id);
    if (!slot) return false;
    return isVirtualWeekdayTen(slot) && a.appointment_datetime === slot.start_datetime;
  });
}
checkpoints.push({
  passed: hasTenAmBooking,
  weight: 0.5
});

// CP2 (0.5): The booked slot is the earliest available weekday 10:00 AM virtual slot
let bookedEarliest = false;
if (earliestSlot && matchingAppointments.length > 0) {
  bookedEarliest = matchingAppointments.some(a => a.slot_id === earliestSlot.id);
}
checkpoints.push({
  passed: bookedEarliest,
  weight: 0.5
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const savedArticles = JSON.parse(localStorage.getItem('saved_articles') || '[]');

const query = 'federal solar tax credit';

// Determine relevant articles (similar to searchArticles)
const relevantArticles = articles.filter(a => {
  if (!a || !a.is_published) return false;
  const pieces = [a.title || '', a.summary || '', a.content || ''];
  if (Array.isArray(a.tags)) pieces.push(a.tags.join(' '));
  const haystack = pieces.join(' ').toLowerCase();
  return haystack.includes(query.toLowerCase());
});

// Sort relevant articles by published_at desc (newest first)
relevantArticles.sort((a, b) => {
  const ad = a.published_at || '';
  const bd = b.published_at || '';
  if (ad === bd) return 0;
  return ad > bd ? -1 : 1;
});

const mostRecentRelevant = relevantArticles[0] || null;

function hasIncentives2024Tag(tags) {
  const arr = Array.isArray(tags) ? tags : [];
  return arr.some(t => typeof t === 'string' && t.toLowerCase() === 'incentives 2024'.toLowerCase());
}

// Saved items whose article is relevant and have the required tag
const qualifyingSaved = savedArticles.filter(sa => {
  const art = articles.find(a => a.id === sa.article_id);
  if (!art || !art.is_published) return false;
  const isRelevant = relevantArticles.some(ra => ra.id === art.id);
  if (!isRelevant) return false;
  return hasIncentives2024Tag(sa.tags);
});

// CP1 (0.6): User saved at least one relevant federal tax credit article with an 'Incentives 2024' tag
checkpoints.push({
  passed: qualifyingSaved.length > 0,
  weight: 0.6
});

// CP2 (0.4): The saved article with that tag is the most recent relevant article
let savedMostRecent = false;
if (mostRecentRelevant && qualifyingSaved.length > 0) {
  savedMostRecent = qualifyingSaved.some(sa => sa.article_id === mostRecentRelevant.id);
}
checkpoints.push({
  passed: savedMostRecent,
  weight: 0.4
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const scenarios = JSON.parse(localStorage.getItem('savings_scenarios') || '[]');

// Scenarios matching the requested inputs and name
const matchingBase = scenarios.filter(s =>
  s &&
  s.name === 'Target $1500+ savings' &&
  s.zip_code === '85001' &&
  s.monthly_electric_bill === 200 &&
  s.roof_orientation === 'south_facing' &&
  s.shading_level === 'low_0_25'
);

// Among those, scenarios achieving at least $1,500 estimated annual savings
const adequateSavings = matchingBase.filter(s =>
  typeof s.estimated_annual_savings === 'number' &&
  s.estimated_annual_savings >= 1500
);

// CP1 (0.4): User saved a scenario with the correct name and input parameters
checkpoints.push({
  passed: matchingBase.length > 0,
  weight: 0.4
});

// CP2 (0.6): That scenario achieves at least $1,500 in estimated annual savings
checkpoints.push({
  passed: adequateSavings.length > 0,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const installers = JSON.parse(localStorage.getItem('installers') || '[]');
const contacts = JSON.parse(localStorage.getItem('installer_contacts') || '[]');

// Qualifying installers according to the task constraints
const qualifyingInstallers = installers.filter(i =>
  i &&
  i.is_active &&
  typeof i.distance_miles === 'number' && i.distance_miles <= 25 &&
  typeof i.overall_rating === 'number' && i.overall_rating >= 4.5 &&
  typeof i.review_count === 'number' && i.review_count >= 50
);

// Sort qualifying installers by rating desc (highest first)
qualifyingInstallers.sort((a, b) => {
  const av = a.overall_rating;
  const bv = b.overall_rating;
  if (av === bv) return 0;
  return bv - av;
});

const topInstaller = qualifyingInstallers[0] || null;

// Contacts sent to qualifying installers
const contactsToQualifiers = contacts.filter(c => {
  const inst = installers.find(i => i.id === c.installer_id);
  return inst && qualifyingInstallers.some(q => q.id === inst.id);
});

// CP1 (0.4): User sent at least one contact message to an installer meeting the distance, rating, and review-count criteria
checkpoints.push({
  passed: contactsToQualifiers.length > 0,
  weight: 0.4
});

// CP2 (0.6): User contacted the top-rated installer among those qualifiers
let contactedTop = false;
if (topInstaller && contactsToQualifiers.length > 0) {
  contactedTop = contactsToQualifiers.some(c => c.installer_id === topInstaller.id);
}
checkpoints.push({
  passed: contactedTop,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const designs = JSON.parse(localStorage.getItem('system_designs') || '[]');
const panelModels = JSON.parse(localStorage.getItem('panel_models') || '[]');
const batteryOptions = JSON.parse(localStorage.getItem('battery_options') || '[]');
const summaryMeta = JSON.parse(localStorage.getItem('task7_summaryViewed') || 'null');

function designMeetsRequirements(design) {
  if (!design) return false;
  if (design.system_type !== 'residential') return false;
  if (design.roof_type !== 'asphalt_shingle') return false;
  if (design.inverter_type !== 'string_inverter') return false;
  if (design.panel_quantity !== 16) return false;
  if (!design.include_battery) return false;
  if (typeof design.battery_capacity_kwh !== 'number' || design.battery_capacity_kwh < 10) return false;

  const panel = panelModels.find(p => p.id === design.panel_model_id);
  if (!panel) return false;
  if (panel.wattage !== 400) return false;
  return true;
}

// Any design in the store that meets the configuration requirements
const validDesigns = designs.filter(d => designMeetsRequirements(d));

// CP1 (0.4): User created a system design that meets all configuration requirements
checkpoints.push({
  passed: validDesigns.length > 0,
  weight: 0.4
});

// CP2 (0.6): The viewed system summary (task7_summaryViewed.designId) corresponds to a design meeting all requirements
let viewedValidSummary = false;
if (summaryMeta && summaryMeta.designId) {
  const viewedDesign = designs.find(d => d.id === summaryMeta.designId);
  viewedValidSummary = designMeetsRequirements(viewedDesign);
}

checkpoints.push({
  passed: viewedValidSummary,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const comparisons = JSON.parse(localStorage.getItem('financing_comparisons') || '[]');
const results = JSON.parse(localStorage.getItem('financing_quote_results') || '[]');
const preApps = JSON.parse(localStorage.getItem('financing_pre_applications') || '[]');

// Pre-applications matching the task context
const taskPreApps = preApps.filter(pa =>
  pa &&
  pa.project_cost === 18000 &&
  pa.zip_code === '60601' &&
  pa.credit_score_range === '680_719' &&
  pa.status === 'draft'
);

// CP1 (0.4): User saved at least one draft pre-application with the correct project cost, ZIP, and credit range
checkpoints.push({
  passed: taskPreApps.length > 0,
  weight: 0.4
});

// All comparisons for this project context
const taskComparisons = comparisons.filter(c =>
  c &&
  c.project_cost === 18000 &&
  c.zip_code === '60601' &&
  c.credit_score_range === '680_719'
);
const taskComparisonIds = taskComparisons.map(c => c.id);

// All quote results for those comparisons
const taskResults = results.filter(r => taskComparisonIds.includes(r.comparison_id));

// Results that meet the upfront and monthly payment constraints
const qualifyingResults = taskResults.filter(r =>
  typeof r.estimated_upfront_payment === 'number' && r.estimated_upfront_payment <= 3000 &&
  typeof r.estimated_monthly_payment === 'number' && r.estimated_monthly_payment <= 150
);

let hasBestQualifyingPreApp = false;
if (qualifyingResults.length > 0 && taskPreApps.length > 0) {
  const minApr = qualifyingResults.reduce((min, r) =>
    (min === null || r.apr < min) ? r.apr : min,
    null
  );

  hasBestQualifyingPreApp = taskPreApps.some(pa =>
    qualifyingResults.some(r =>
      r.financing_option_id === pa.financing_option_id &&
      r.term_years === pa.term_years &&
      r.apr === minApr
    )
  );
}

// CP2 (0.6): The saved pre-application uses the lowest-APR option among qualifying financing results
checkpoints.push({
  passed: hasBestQualifyingPreApp,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
